import React, { useState } from 'react';
import axios from 'axios';

function PlayerForm() {

  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [iscoach, setIsCoach] = useState(false);

  function submitPlayer(event) {
    event.preventDefault();
    alert(`Form submitted with firstName: ${firstName}, lastName: ${lastName}, iscoach: ${iscoach}`);
    axios.post('http://localhost:4000/players', {
      firstName: firstName,
      lastName: lastName,
      email: email,
      phone: phone,
      iscoach: iscoach,
    })
    .then((response) => {
      console.log(response);
    })
    .catch((error) => {
      console.log(error);
    });
  }

  function handleCheckBox(event) {
    setIsCoach(event.target.checked);
  }
  
  return ( 
    <div className="row">
      <h1 className='center'>Add a new player</h1>
      <form className="col s12" onSubmit={submitPlayer}>
        <div className="row">
          <div className="input-field col s6">
            <input id="firstName" name="firstName" type="text" value={firstName} onChange={(event) => setFirstName(event.target.value)} />
            <label htmlFor="firstName">First Name</label>
          </div>
          <div className="input-field col s6">
            <input id="lastName" name="lastName" type="text" value={lastName} onChange={(event) => setLastName(event.target.value)} />
            <label htmlFor="lastName">Last Name</label>
          </div>
          <div className="input-field col s6">
            <input id="email" name="email" type="email" value={email} onChange={(event) => setEmail(event.target.value)} />
            <label htmlFor="email">Email</label>
          </div>
          <div className="input-field col s6">
            <input id="phone" name="phone"  type="tel" value={phone} onChange={(event) => setPhone(event.target.value)} />
            <label htmlFor="phone">Phone</label>
          </div>
          <div className="input-field col s6">
            <label>
              <input id="iscoach" name="iscoach" className="filled-in" type="checkbox" checked={iscoach} onChange={handleCheckBox} />
              <span>Is Coach?</span>
            </label>
          </div>
          <div className="input-field col s6">
            <input id="team" name="team" type="text" />
            <label htmlFor="team">Team</label>
          </div>
          <div className="input-field col s6">
            <input id="speed" name="speed" type="number" max="3" />
            <label htmlFor="speed">Speed</label>
          </div>
          <div className="input-field col s6">
            <input id="strength" name="strength" type="number" max="3" />
            <label htmlFor="strength">Strength</label>
          </div>
          <div className="input-field col s6">
            <input id="endurance" name="endurance" type="number" max="3" />
            <label htmlFor="endurance">Endurance</label>
          </div>
          <div className="input-field col s6">
            <input id="ability" name="ability" type="number" max="3" />
            <label htmlFor="ability">Ability</label>
          </div>
          <div className="input-field col s6">
            <input id="techniques" name="techniques" type="number" max="3" />
            <label htmlFor="techniques">Techniques</label>
          </div>
          <div className="input-field col s6">
            <input id="tactical" name="tactical" type="number" max="3" />
            <label htmlFor="tactical">Tactical</label>
          </div>
        </div>
        {firstName} {lastName} {iscoach.toString()}
        <button className='btn waves-effect waves-light' type='submit' name='action'>Add Player</button>
      </form>
    </div>
  );
}

export default PlayerForm;
